mapper.select:
SELECT

FROM chat_session
WHERE status = 'active'
  AND updated_at < #{cutoff}
ORDER BY updated_at ASC
LIMIT #{limit}

SELECT

FROM chat_session
WHERE status = 'active'
  AND updated_at <= #{cutoff}
  AND message_count > #{minMessages}
  AND (
    summary_status = 'pending'
    OR (summary_status = 'failed' AND summary_retry_count < #{maxRetryCount})
  )
ORDER BY updated_at ASC
LIMIT #{limit}

mapper.update:
UPDATE chat_session
SET summary_status = 'processing',
    summary_attempted_at = #{attemptedAt},
    summary_error = NULL
WHERE session_id = #{sessionId}
  AND summary_status IN ('pending', 'failed')
  AND updated_at <= #{cutoff}
  AND message_count > #{minMessages}

UPDATE chat_session
SET summary_status = 'failed',
    summary_retry_count = COALESCE(summary_retry_count, 0) + 1,
    summary_error = #{error},
    summary_attempted_at = #{attemptedAt}
WHERE session_id = #{sessionId}
